import{_ as t,c as a,o as i,ag as l}from"./chunks/framework.DD2hp6gW.js";const f=JSON.parse('{"title":"File Upload Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/file-upload.md","filePath":"fields/file-upload.md","lastUpdated":null}'),o={name:"fields/file-upload.md"};function r(s,e,n,d,c,g){return i(),a("div",null,e[0]||(e[0]=[l('<h1 id="file-upload-field" tabindex="-1">File Upload Field <a class="header-anchor" href="#file-upload-field" aria-label="Permalink to &quot;File Upload Field&quot;">​</a></h1><p>The <strong>File Upload</strong> field allows customers to attach files (images, documents, etc.) to their order. OptionBay handles the upload via the WordPress media system and validates the file against your configured restrictions during server-side processing.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Uploading a custom logo for printing on merchandise</li><li>Attaching a reference photo for a custom illustration</li><li>Submitting a PDF document (e.g., a resume for a printing service)</li><li>Uploading a design file for laser engraving or 3D printing</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a File Upload field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the upload area (e.g., &quot;Upload Your Logo&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the field (e.g., &quot;Accepted formats: JPG, PNG. Max 5MB.&quot;).</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must upload a file before adding the product to the cart.</td></tr></tbody></table><h3 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h3><p>Since the File Upload is not an options-based field, pricing is configured at the <strong>field level</strong>:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">Choose how the field affects the product price. Available types: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>.</td></tr><tr><td style="text-align:left;"><strong>Price Amount</strong></td><td style="text-align:left;">The numeric value to add when a file is uploaded. For example, charge a flat $10 fee for logo customization.</td></tr></tbody></table><h3 id="file-restrictions" tabindex="-1">File Restrictions <a class="header-anchor" href="#file-restrictions" aria-label="Permalink to &quot;File Restrictions&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Allowed Extensions</strong></td><td style="text-align:left;">A comma-separated list of permitted file extensions (e.g., <code>.jpg,.png,.pdf,.svg</code>). If left empty, all common file types are accepted.</td></tr><tr><td style="text-align:left;"><strong>Max File Size (MB)</strong></td><td style="text-align:left;">The maximum allowed file size in megabytes. Files exceeding this limit will be rejected during validation. Defaults to <code>5</code> MB.</td></tr></tbody></table><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Make sure your server&#39;s <code>upload_max_filesize</code> and <code>post_max_size</code> PHP settings are at least as large as the Max File Size you configure here. Otherwise, PHP itself will reject the upload before OptionBay can process it.</p></div><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Upload Your Logo&quot; field only when the customer selects &quot;Custom Print&quot; from a dropdown.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',17)]))}const p=t(o,[["render",r]]);export{f as __pageData,p as default};
